external_knowledge:
; This assumes that "conducted by subjects who also participated in experiments led by John Doe" is understood as subjects who have taken part in at least one experiment led by John Doe; 
; The term "average reaction time" refers to the mean value of reaction times recorded for a particular set of trials; 
; "Reaction time" is the time taken by a subject to react to a given stimulus, usually measured in milliseconds.

sql:
SELECT trial_id, subject_id
FROM trials
WHERE accuracy = 1 AND rt < 500;

SELECT cognitive_ability_score 
FROM subjects 
WHERE subject_id = '1';

SELECT AVG(rt) AS average_reaction_time
FROM trials
WHERE experiment_id = 'exp1';
